// @ts-nocheck
import { createManager } from './i18n-core.min.js';
import { DEFAULT_LOCALE, GLOBAL_KEY, ROOT_REF, SHORT_TO_CANONICAL, getAdapterDictionaries, } from './i18n-conf.js';
import deDE from '../de-DE.js';
import enUS from '../en-US.js';
import esES from '../es-ES.js';
import frFR from '../fr-FR.js';
import ptBR from '../pt-BR.js';
import zhCN from '../zh-CN.js';
const STATIC_DICTIONARIES = {
    'de-DE': deDE,
    'en-US': enUS,
    'es-ES': esES,
    'fr-FR': frFR,
    'pt-BR': ptBR,
    'zh-CN': zhCN,
};
const manager = createManager({
    defaultLocale: DEFAULT_LOCALE,
    globalKey: GLOBAL_KEY,
    shortToCanonical: SHORT_TO_CANONICAL,
    dictionaries: getAdapterDictionaries(STATIC_DICTIONARIES),
    rootRef: ROOT_REF,
});
export const AVAILABLE_LANGUAGES = [];
function syncAvailableLanguages() {
    AVAILABLE_LANGUAGES.splice(0, AVAILABLE_LANGUAGES.length, ...manager.getAvailableLocales());
}
syncAvailableLanguages();
export const createI18n = (options) => manager.createI18n(options);
export const getStrings = (locale) => manager.getStrings(locale);
export const normalizeLocale = (locale, fallback) => manager.normalizeLocale(locale, fallback);
export const getLocaleFromEnvironment = () => manager.getLocaleFromEnvironment();
export const getLocaleFromDocument = () => manager.getLocaleFromDocument();
export const hasLocale = (locale) => manager.hasLocale(locale);
export const registerLocale = (locale, strings) => {
    const result = manager.registerLocale(locale, strings);
    syncAvailableLanguages();
    return result;
};
export const registerLocales = (locales) => {
    const registeredLocales = [];
    Object.entries(locales || {}).forEach(([locale, strings]) => {
        if (registerLocale(locale, strings)) {
            registeredLocales.push(normalizeLocale(locale, locale));
        }
    });
    syncAvailableLanguages();
    return registeredLocales;
};
export const loadLocale = async (locale, options) => {
    const loaded = await manager.loadLocale(locale, options);
    syncAvailableLanguages();
    return loaded;
};
export default manager;
